"use strict";const r=require("../utils/request.js");exports.cancelOrder=function(e){return r.request({url:`/orders/${e}/cancel`,method:"PUT"})},exports.confirmOrder=function(e){return r.request({url:`/orders/${e}/confirm`,method:"PUT"})},exports.createOrder=function(e){return r.request({url:"/orders",method:"POST",data:e})},exports.getBuyOrders=function(){return r.request({url:"/orders/buy",method:"GET"})},exports.getOrderDetail=function(e){return r.request({url:`/orders/${e}`,method:"GET"})},exports.getSellOrders=function(){return r.request({url:"/orders/sell",method:"GET"})};
